# 配置/历史/聊天图片 固定放在应用数据目录, 不随接收目录移动
def _app_data_dir():
    system = platform.system()
    if system == "Windows":
        base = Path(os.environ.get("APPDATA", Path.home()))
    elif system == "Darwin":
        base = Path.home() / "Library" / "Application Support"
    else:
        base = Path(os.environ.get("XDG_CONFIG_HOME", Path.home() / ".config"))
    return base / "BitFerry"

APP_DATA = _app_data_dir()
IMG_DIR = APP_DATA / "images"               # 聊天图片落地(固定)
HISTORY_FILE = APP_DATA / "chat_history.json"
DEVICES_FILE = APP_DATA / "known_devices.json"
SETTINGS_FILE = APP_DATA / "settings.json"

# 接收文件的默认根目录(可被用户修改)
DEFAULT_RECV_ROOT = Path.home() / "BitFerry_Received"
RECV_ROOT = DEFAULT_RECV_ROOT               # 运行时全局, 接收线程引用


def load_recv_root():
    """从设置读取接收目录, 没有则用默认。"""
    try:
        s = json.loads(SETTINGS_FILE.read_text(encoding="utf-8"))
        p = s.get("recv_root")
        if p:
            return Path(p)
    except Exception:
        pass
    return DEFAULT_RECV_ROOT


def save_recv_root(path):
    set_setting("recv_root", str(path))


DEFAULT_SHORTCUT = "Ctrl+Shift+A" if platform.system() != "Darwin" else "Meta+Shift+A"


def _read_settings():
    try:
        return json.loads(SETTINGS_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def set_setting(key, value):
    try:
        APP_DATA.mkdir(parents=True, exist_ok=True)
        s = _read_settings()
        s[key] = value
        SETTINGS_FILE.write_text(json.dumps(s, ensure_ascii=False), encoding="utf-8")
    except Exception:
        pass


def get_setting(key, default=None):
    return _read_settings().get(key, default)


def load_shortcut():
    return get_setting("shot_shortcut", DEFAULT_SHORTCUT)


