# ----------------------------- 工具函数 -----------------------------
def get_local_ip():
    s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    try:
        s.connect(("8.8.8.8", 80))
        ip = s.getsockname()[0]
    except Exception:
        ip = "127.0.0.1"
    finally:
        s.close()
    return ip


def get_broadcast_addrs():
    """所有本机接口的子网广播地址列表（兼容多网卡 + 修复 Windows 防火墙拦截广播）。
    同时覆盖 255.255.255.255 和每张网卡对应的 x.x.x.255 定向广播。"""
    addrs = {"255.255.255.255"}
    ips = set()
    # 1. 通过 getaddrinfo 获取本机所有 IPv4 地址（覆盖多网卡）
    try:
        for info in socket.getaddrinfo(socket.gethostname(), None):
            if info[0] == socket.AF_INET:
                ips.add(info[4][0])
    except Exception:
        pass
    # 2. 主路由 IP 兜底
    ips.add(get_local_ip())
    # 3. 每个 IP 对应的 /24 子网广播
    for ip in ips:
        if ip.startswith("127.") or ip == "0.0.0.0":
            continue
        parts = ip.split(".")
        if len(parts) == 4:
            bcast = f"{parts[0]}.{parts[1]}.{parts[2]}.255"
            addrs.add(bcast)
    return list(addrs)


def _try_open_win_firewall():
    """Windows: 静默尝试添加防火墙入站规则，失败则忽略(需要管理员时跳过)。"""
    if platform.system() != "Windows":
        return
    try:
        exe = sys.executable
        for proto, port in [("UDP", DISCOVERY_PORT), ("TCP", TRANSFER_PORT)]:
            name = f"BitFerry-{proto}-{port}"
            subprocess.run(
                ["netsh", "advfirewall", "firewall", "add", "rule",
                 f"name={name}", "dir=in", "action=allow",
                 f"protocol={proto}", f"localport={port}",
                 f"program={exe}", "enable=yes"],
                capture_output=True, timeout=5)
    except Exception:
        pass


def get_hostname():
    return socket.gethostname()


def safe_folder_name(name):
    bad = '<>:"/\\|?*'
    return "".join("_" if c in bad else c for c in name).strip() or "Unknown"


def recv_exact(sock, n):
    buf = bytearray()
    while len(buf) < n:
        chunk = sock.recv(min(CHUNK, n - len(buf)))
        if not chunk:
            raise ConnectionError("连接中断")
        buf.extend(chunk)
    return bytes(buf)


def human_size(n):
    for unit in ("B", "KB", "MB", "GB"):
        if n < 1024:
            return f"{n:.0f} {unit}" if unit == "B" else f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} TB"


def now_hm():
    return datetime.now().strftime("%H:%M")


# ----------------------------- 主动截图(系统级) -----------------------------
def take_screenshot(get_clipboard_image=None):
    """
    区域截图。
    - macOS: screencapture -i 交互式区域选择, 直接出图。
    - Windows: 调用系统截图工具(新版 ms-screenclip / 旧版 snippingtool /clip)做区域选择,
               结果在剪贴板, 通过 get_clipboard_image 回调取出。
    get_clipboard_image: 可选回调, 返回 QImage 或 None (从 Qt 剪贴板读图, 需在主线程预备好)。
    返回截图文件路径, 取消或失败返回 None。
    """
    tmp = Path(tempfile.gettempdir()) / f"lantong_shot_{int(time.time())}.png"
    system = platform.system()
    try:
        if system == "Darwin":
            # -i 交互式区域截图(用户拖选区域); 取消则不生成文件
            subprocess.run(["screencapture", "-i", str(tmp)], check=True)
            if tmp.exists() and tmp.stat().st_size > 0:
                return str(tmp)
            return None

        if system == "Windows":
            return _windows_region_screenshot(tmp, get_clipboard_image)

        # Linux 等: 尝试区域工具, 退回全屏
        for cmd in (["gnome-screenshot", "-a", "-f", str(tmp)],
                    ["spectacle", "-r", "-b", "-n", "-o", str(tmp)],
                    ["scrot", "-s", str(tmp)]):
            try:
                subprocess.run(cmd, check=True)
                if tmp.exists() and tmp.stat().st_size > 0:
                    return str(tmp)
            except Exception:
                continue
        try:
            import mss
            with mss.mss() as sct:
                sct.shot(output=str(tmp))
            return str(tmp)
        except Exception:
            from PIL import ImageGrab
            ImageGrab.grab().save(str(tmp))
            return str(tmp)
    except Exception as e:
        print("截图失败:", e)
        return None


def _windows_region_screenshot(tmp, get_clipboard_image):
    """Windows 区域截图: 启动系统截图工具 -> 用户选区 -> 从剪贴板取图。"""
    # 记录调用前剪贴板序列号(用于判断用户是否真的截了新图)
    import ctypes
    try:
        user32 = ctypes.windll.user32
        before_seq = user32.GetClipboardSequenceNumber()
    except Exception:
        before_seq = None

    launched = False
    # 新版 Windows 10/11: ms-screenclip 协议直接进入区域截图模式
    for cmd in (
        ["explorer.exe", "ms-screenclip:"],
        ["snippingtool.exe", "/clip"],
    ):
        try:
            subprocess.Popen(cmd)
            launched = True
            break
        except Exception:
            continue
    if not launched:
        # 都失败则退回全屏
        try:
            import mss
            with mss.mss() as sct:
                sct.shot(output=str(tmp))
            return str(tmp)
        except Exception:
            return None

    # 轮询剪贴板, 等待用户完成选区(最多约 60 秒)
    import ctypes
    deadline = time.time() + 60
    while time.time() < deadline:
        time.sleep(0.4)
        try:
            seq = ctypes.windll.user32.GetClipboardSequenceNumber()
        except Exception:
            seq = None
        if before_seq is not None and seq is not None and seq == before_seq:
            continue  # 剪贴板还没变, 用户还在截或没开始
        # 剪贴板变了 -> 尝试取图
        img = get_clipboard_image() if get_clipboard_image else None
        if img is not None:
            try:
                img.save(str(tmp), "PNG")
                if tmp.exists() and tmp.stat().st_size > 0:
                    return str(tmp)
            except Exception:
                pass
        # 剪贴板变了但不是图片(可能用户复制了别的), 继续等一会儿
    return None


# ===================================================================
#  协议层: 在同一 TCP 端口上传输三类消息
#    kind="file"  -> 普通文件, 落到 机器名/ 子目录 (保持原行为)
#    kind="text"  -> 聊天文字
#    kind="image" -> 聊天图片(截图/粘贴)
#  统一帧格式: MAGIC | 4字节头长 | JSON头 | 可选二进制负载
# ===================================================================
class Discovery:
    def __init__(self, hostname, on_peers_change):
        self.hostname = hostname
        self.on_peers_change = on_peers_change
        self.peers = {}
        self.lock = threading.Lock()
        self.running = True
        self.local_ip = get_local_ip()
        self._reply_times = {}   # ip -> 上次单播回应时间，用于限速

    def _make_msg(self):
        return json.dumps({
            "type": "announce", "name": self.hostname,
            "ip": self.local_ip, "port": TRANSFER_PORT,
        }).encode("utf-8")

    def start(self):
        threading.Thread(target=self._broadcaster, daemon=True).start()
        threading.Thread(target=self._listener, daemon=True).start()
        threading.Thread(target=self._reaper, daemon=True).start()

    def stop(self):
        self.running = False

    def ping_known(self, ips):
        """启动后向所有历史已知设备单播 announce，加速初始发现（尤其 Windows 防火墙场景）。"""
        def _do():
            time.sleep(0.8)   # 等 listener 线程就绪
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                msg = self._make_msg()
                for ip in ips:
                    if ip != self.local_ip:
                        try:
                            s.sendto(msg, (ip, DISCOVERY_PORT))
                        except Exception:
                            pass
                s.close()
            except Exception:
                pass
        threading.Thread(target=_do, daemon=True).start()

    def force_broadcast(self):
        """立即广播 + 单播到所有当前已知对端（刷新按钮触发）。"""
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
            msg = self._make_msg()
            for addr in get_broadcast_addrs():
                try:
                    s.sendto(msg, (addr, DISCOVERY_PORT))
                except Exception:
                    pass
            with self.lock:
                peer_ips = list(self.peers.keys())
            for ip in peer_ips:
                try:
                    s.sendto(msg, (ip, DISCOVERY_PORT))
                except Exception:
                    pass
            s.close()
        except Exception:
            pass

    def _unicast_reply(self, target_ip):
        """收到对端广播后，向其 IP 单播一次 announce。
        Windows 防火墙通常允许单播到已绑定端口，但会拦截入站广播。"""
        now = time.time()
        if now - self._reply_times.get(target_ip, 0) < BROADCAST_INTERVAL:
            return   # 限速：避免每 2 秒都发一次
        self._reply_times[target_ip] = now
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.sendto(self._make_msg(), (target_ip, DISCOVERY_PORT))
            s.close()
        except Exception:
            pass

    def _broadcaster(self):
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
        bcast_addrs = get_broadcast_addrs()
        msg = self._make_msg()
        while self.running:
            for addr in bcast_addrs:
                try:
                    s.sendto(msg, (addr, DISCOVERY_PORT))
                except Exception:
                    pass
            time.sleep(BROADCAST_INTERVAL)

    def _listener(self):
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)  # Windows 接收广播包必需
        try:
            s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEPORT, 1)
        except (AttributeError, OSError):
            pass
        s.bind(("", DISCOVERY_PORT))
        s.settimeout(1.0)
        while self.running:
            try:
                data, addr = s.recvfrom(2048)
                info = json.loads(data.decode("utf-8"))
                if info.get("type") != "announce":
                    continue
                ip = info.get("ip", addr[0])
                if ip == self.local_ip:
                    continue
                with self.lock:
                    self.peers[ip] = {
                        "name": info.get("name", ip),
                        "port": info.get("port", TRANSFER_PORT),
                        "last": time.time(),
                    }
                self.on_peers_change(self.snapshot())
                # 关键：单播回应对端，让对端即使收不到广播也能发现我们
                threading.Thread(target=self._unicast_reply, args=(ip,),
                                 daemon=True).start()
            except socket.timeout:
                continue
            except Exception:
                continue

    def _reaper(self):
        while self.running:
            now = time.time()
            changed = False
            with self.lock:
                for ip, p in list(self.peers.items()):
                    online = (now - p["last"]) <= PEER_TIMEOUT
                    if p.get("_online") != online:
                        p["_online"] = online
                        changed = True
            if changed:
                self.on_peers_change(self.snapshot())
            time.sleep(1.5)

    def snapshot(self):
        now = time.time()
        with self.lock:
            out = {}
            for ip, p in self.peers.items():
                out[ip] = {
                    "name": p["name"], "port": p["port"],
                    "online": (now - p["last"]) <= PEER_TIMEOUT,
                }
            return out


class Receiver:
    """统一接收: 文件 / 文字 / 图片。"""
    def __init__(self, on_file, on_chat, on_log):
        self.on_file = on_file        # (path, sender)
        self.on_chat = on_chat        # (sender_name, sender_ip, kind, payload)
        self.on_log = on_log
        self.running = True

    def start(self):
        threading.Thread(target=self._serve, daemon=True).start()

    def stop(self):
        self.running = False

    def _serve(self):
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        try:
            s.bind(("", TRANSFER_PORT))
            s.listen(8)
            s.settimeout(1.0)
        except Exception as e:
            self.on_log(f"无法监听端口 {TRANSFER_PORT}: {e}", "error")
            return
        while self.running:
            try:
                conn, addr = s.accept()
            except socket.timeout:
                continue
            except Exception:
                continue
            threading.Thread(target=self._handle, args=(conn, addr),
                             daemon=True).start()

    def _handle(self, conn, addr):
        try:
            if recv_exact(conn, 4) != MAGIC:
                return
            (hlen,) = struct.unpack(">I", recv_exact(conn, 4))
            header = json.loads(recv_exact(conn, hlen).decode("utf-8"))
            kind = header.get("kind", "file")
            sender = header.get("sender", addr[0])
            sender_ip = addr[0]
            size = header.get("size", 0)

            if kind == "text":
                self.on_chat(sender, sender_ip, "text", header.get("text", ""))
                return

            if kind == "batch":
                self._handle_batch(conn, header, sender, sender_ip)
                return

            # 只接受已知的 file / image 单条类型; 未知类型直接拒收,
            # 避免对端版本不一致时把整帧当成文件写成 file.bin。
            if kind not in ("file", "image"):
                self.on_log(
                    f"收到无法识别的消息(来自 {sender})。可能对方 LanTong 版本较旧，"
                    f"请让双方都更新到最新版本。", "error")
                return

            # file / image 都带二进制负载
            data = bytearray()
            while len(data) < size:
                chunk = conn.recv(min(CHUNK, size - len(data)))
                if not chunk:
                    break
                data.extend(chunk)
            if len(data) != size:
                self.on_log(f"{header.get('filename','?')} 接收不完整", "error")
                return

            if kind == "image":
                IMG_DIR.mkdir(parents=True, exist_ok=True)
                fn = f"recv_{int(time.time()*1000)}.png"
                path = IMG_DIR / fn
                with open(path, "wb") as f:
                    f.write(data)
                self.on_chat(sender, sender_ip, "image", str(path))
            else:  # file -> 按机器名归档
                folder = safe_folder_name(sender)
                dest_dir = globals()["RECV_ROOT"] / folder
                dest_dir.mkdir(parents=True, exist_ok=True)
                filename = os.path.basename(header.get("filename", "file.bin"))
                dest = dest_dir / filename
                b, e = os.path.splitext(filename)
                i = 1
                while dest.exists():
                    dest = dest_dir / f"{b}_{i}{e}"
                    i += 1
                with open(dest, "wb") as f:
                    f.write(data)
                self.on_log(f"收到 {dest.name} · 来自 {sender} · {human_size(size)}", "recv")
                self.on_file(str(dest), sender)
        except Exception as e:
            self.on_log(f"接收失败: {e}", "error")
        finally:
            conn.close()

    def _handle_batch(self, conn, header, sender, sender_ip):
        """接收一批消息: header.parts 描述每个部件, 之后是各二进制负载顺序拼接。"""
        parts = header.get("parts", [])
        folder = safe_folder_name(sender)
        out_parts = []          # 给 UI 的渲染部件 [{type, ...}]
        IMG_DIR.mkdir(parents=True, exist_ok=True)
        for part in parts:
            ptype = part.get("type")
            if ptype == "text":
                out_parts.append({"type": "text", "text": part.get("text", "")})
            elif ptype == "image":
                size = part.get("size", 0)
                data = self._recv_n(conn, size)
                fn = f"recv_{int(time.time()*1000*1000)%10**13}.png"
                path = IMG_DIR / fn
                with open(path, "wb") as f:
                    f.write(data)
                out_parts.append({"type": "image", "path": str(path)})
            elif ptype == "file":
                size = part.get("size", 0)
                data = self._recv_n(conn, size)
                dest_dir = globals()["RECV_ROOT"] / folder
                dest_dir.mkdir(parents=True, exist_ok=True)
                filename = os.path.basename(part.get("filename", "file.bin"))
                rel = part.get("relpath")  # 文件夹内相对路径
                if rel:
                    dest = dest_dir / rel
                    dest.parent.mkdir(parents=True, exist_ok=True)
                else:
                    dest = dest_dir / filename
                    b, e = os.path.splitext(filename)
                    i = 1
                    while dest.exists():
                        dest = dest_dir / f"{b}_{i}{e}"
                        i += 1
                with open(dest, "wb") as f:
                    f.write(data)
                out_parts.append({"type": "file", "name": filename,
                                  "size": size, "path": str(dest)})
                self.on_file(str(dest), sender)
        self.on_log(f"收到一批消息 · 来自 {sender} · {len(parts)} 项", "recv")
        # 通过 on_chat 传 batch, payload 用 JSON 字符串承载 parts
        self.on_chat(sender, sender_ip, "batch", json.dumps(out_parts, ensure_ascii=False))

    def _recv_n(self, conn, n):
        data = bytearray()
        while len(data) < n:
            chunk = conn.recv(min(CHUNK, n - len(data)))
            if not chunk:
                break
            data.extend(chunk)
        return bytes(data)


def _send_frame(peer_ip, peer_port, header, payload=b""):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(10.0)
    s.connect((peer_ip, peer_port))
    s.settimeout(None)
    hb = json.dumps(header).encode("utf-8")
    s.sendall(MAGIC)
    s.sendall(struct.pack(">I", len(hb)))
    s.sendall(hb)
    if payload:
        s.sendall(payload)
    s.close()


def send_text(text, peer_ip, peer_port, sender_name, on_log):
    try:
        _send_frame(peer_ip, peer_port,
                    {"kind": "text", "sender": sender_name, "text": text})
        return True
    except Exception as e:
        on_log(f"消息发送失败: {e}", "error")
        return False


def send_image_bytes(data, peer_ip, peer_port, sender_name, on_log):
    try:
        _send_frame(peer_ip, peer_port,
                    {"kind": "image", "sender": sender_name, "size": len(data),
                     "filename": "image.png"}, data)
        return True
    except Exception as e:
        on_log(f"图片发送失败: {e}", "error")
        return False


def send_file(filepath, peer_ip, peer_port, sender_name, on_log):
    try:
        filepath = Path(filepath)
        with open(filepath, "rb") as f:
            data = f.read()
        _send_frame(peer_ip, peer_port,
                    {"kind": "file", "sender": sender_name,
                     "filename": filepath.name, "size": len(data)}, data)
        on_log(f"已发送 {filepath.name} → {peer_ip}", "send")
        return True
    except Exception as e:
        on_log(f"发送 {filepath.name} 失败: {e}", "error")
        return False


def send_batch(items, peer_ip, peer_port, sender_name, on_log):
    """
    一次性发送一批内容(文字/图片/文件)作为单个消息块。
    items: 列表, 每项形如:
        {"type":"text", "text":...}
        {"type":"image", "bytes":b"..."}                       # 内存图片(粘贴/截图)
        {"type":"image", "path":"..."}                         # 磁盘图片
        {"type":"file", "path":"...", "relpath":可选}          # 文件
    协议: header(kind=batch, parts=[...]) + 所有二进制负载顺序拼接
    """
    try:
        parts = []
        blobs = []
        for it in items:
            t = it["type"]
            if t == "text":
                parts.append({"type": "text", "text": it["text"]})
            elif t == "image":
                if "bytes" in it:
                    data = it["bytes"]
                else:
                    data = Path(it["path"]).read_bytes()
                parts.append({"type": "image", "size": len(data)})
                blobs.append(data)
            elif t == "file":
                p = Path(it["path"])
                data = p.read_bytes()
                part = {"type": "file", "filename": p.name, "size": len(data)}
                if it.get("relpath"):
                    part["relpath"] = it["relpath"]
                parts.append(part)
                blobs.append(data)

        header = {"kind": "batch", "sender": sender_name, "parts": parts}
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(15.0)
        s.connect((peer_ip, peer_port))
        s.settimeout(None)
        hb = json.dumps(header).encode("utf-8")
        s.sendall(MAGIC)
        s.sendall(struct.pack(">I", len(hb)))
        s.sendall(hb)
        for blob in blobs:
            s.sendall(blob)
        s.close()
        on_log(f"已发送一批消息 → {peer_ip}（{len(parts)} 项）", "send")
        return True
    except Exception as e:
        on_log(f"批量发送失败: {e}", "error")
        return False


