def _open_path(path):
    system = platform.system()
    try:
        if system == "Darwin":
            subprocess.run(["open", path])
        elif system == "Windows":
            os.startfile(path)  # type: ignore
        else:
            subprocess.run(["xdg-open", path])
    except Exception:
        pass


class ClickableImage(QLabel):
    def __init__(self, path, pix):
        super().__init__()
        self.path = path
        self.setPixmap(pix)
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self.setObjectName("chatImage")
        self.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.customContextMenuRequested.connect(self._menu)

    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            _open_path(self.path)

    def _menu(self, pos):
        from PyQt6.QtWidgets import QMenu as _QMenu, QFileDialog as _QFD
        m = _QMenu(self)
        act_save = m.addAction("图片另存为…")
        act_open = m.addAction("打开图片")
        act_folder = m.addAction("在文件夹中显示")
        chosen = m.exec(self.mapToGlobal(pos))
        if chosen == act_save:
            self._save_as()
        elif chosen == act_open:
            _open_path(self.path)
        elif chosen == act_folder:
            self._reveal()

    def _save_as(self):
        from PyQt6.QtWidgets import QFileDialog as _QFD
        if not (self.path and os.path.exists(self.path)):
            return
        suffix = Path(self.path).suffix or ".png"
        default = f"截图_{int(time.time())}{suffix}"
        dest, _ = _QFD.getSaveFileName(self, "保存截图到…", default,
                                       "图片 (*.png *.jpg *.jpeg *.bmp);;所有文件 (*.*)")
        if dest:
            try:
                import shutil
                shutil.copy2(self.path, dest)
            except Exception:
                try:
                    Path(dest).write_bytes(Path(self.path).read_bytes())
                except Exception:
                    pass

    def _reveal(self):
        if not (self.path and os.path.exists(self.path)):
            return
        system = platform.system()
        try:
            if system == "Darwin":
                subprocess.run(["open", "-R", self.path])
            elif system == "Windows":
                subprocess.run(["explorer", "/select,", os.path.normpath(self.path)])
            else:
                subprocess.run(["xdg-open", str(Path(self.path).parent)])
        except Exception:
            pass


