class Bubble(QFrame):
    def __init__(self, kind, payload, mine, ts, name):
        super().__init__()
        self.setObjectName("bubbleRow")
        row = QHBoxLayout(self)
        row.setContentsMargins(0, 4, 0, 4)

        col = QVBoxLayout()
        col.setSpacing(3)

        meta = QLabel(f"{name} · {ts}")
        meta.setObjectName("bubbleMeta")
        meta.setAlignment(Qt.AlignmentFlag.AlignRight if mine
                          else Qt.AlignmentFlag.AlignLeft)

        body = QFrame()
        body.setObjectName("bubbleMine" if mine else "bubbleTheirs")
        bl = QVBoxLayout(body)
        bl.setContentsMargins(12, 9, 12, 9)
        bl.setSpacing(7)

        # 统一成 parts 列表渲染
        parts = self._normalize(kind, payload)
        for part in parts:
            self._add_part(bl, part, mine)

        col.addWidget(meta)
        col.addWidget(body)

        if mine:
            row.addStretch()
            row.addLayout(col)
        else:
            row.addLayout(col)
            row.addStretch()

    def _normalize(self, kind, payload):
        """把旧的 text/image 单条 与 新的 batch 统一成 parts 列表。"""
        if kind == "batch":
            try:
                return json.loads(payload)
            except Exception:
                return [{"type": "text", "text": "[消息解析失败]"}]
        if kind == "text":
            return [{"type": "text", "text": payload}]
        if kind == "image":
            return [{"type": "image", "path": payload}]
        return [{"type": "text", "text": str(payload)}]

    def _add_part(self, bl, part, mine):
        t = part.get("type")
        if t == "text":
            txt = part.get("text", "")
            if not txt:
                return
            lbl = QLabel(txt)
            lbl.setObjectName("bubbleTextMine" if mine else "bubbleText")
            lbl.setWordWrap(True)
            lbl.setMaximumWidth(420)
            lbl.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)
            bl.addWidget(lbl)
        elif t == "image":
            path = part.get("path", "")
            pix = QPixmap(path)
            if not pix.isNull():
                if pix.width() > 320:
                    pix = pix.scaledToWidth(320, Qt.TransformationMode.SmoothTransformation)
                bl.addWidget(ClickableImage(path, pix))
            else:
                bl.addWidget(QLabel("[图片无法显示]"))
        elif t == "file":
            bl.addWidget(FileCard(part.get("name", "文件"),
                                  part.get("size", 0),
                                  part.get("path", ""), mine))


