class ShortcutCapture(QLabel):
    """点击后捕获下一个按键组合, 显示为快捷键字符串。"""
    captured = pyqtSignal(str)

    def __init__(self, current):
        super().__init__(current or "点击此处后按下快捷键")
        self.setObjectName("shortcutBox")
        self.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.setMinimumHeight(44)
        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self._seq = current

    def mousePressEvent(self, e):
        self.setText("请按下快捷键…")
        self.setFocus()

    def keyPressEvent(self, e):
        key = e.key()
        mods = e.modifiers()
        # 忽略单独的修饰键
        if key in (Qt.Key.Key_Control, Qt.Key.Key_Shift, Qt.Key.Key_Alt,
                   Qt.Key.Key_Meta, Qt.Key.Key_unknown):
            return
        seq = QKeySequence(key | int(mods.value)).toString()
        if seq:
            self._seq = seq
            self.setText(seq)
            self.captured.emit(seq)

    def sequence(self):
        return self._seq


